def findNumberOfLIS(self, nums):
    n = len(nums)
    lis_lengths = [1] * n
    for i in range(1, n):
        for j in range(i):
            if nums[i] > nums[j] and lis_lengths[i] < lis_lengths[j] + 1:
                lis_lengths[i] = lis_lengths[j] + 1
    return max(lis_lengths)

